// PTZ operation log display
function ptzLog(msg, type='info') {
    const box = document.getElementById('ptzLogBox');
    if (!box) return;
    const time = new Date().toLocaleTimeString();
    const colors = {
        'info': '#8b949e',
        'success': '#3fb950',
        'error': '#f85149',
        'warning': '#d29922',
        'debug': '#58a6ff'
    };
    const icons = {
        'info': 'ℹ️',
        'success': '✅',
        'error': '❌',
        'warning': '⚠️',
        'debug': '🔧'
    };
    const entry = `<div style="color:${colors[type]};margin:2px 0">${icons[type]} ${time} ${msg}</div>`;
    box.innerHTML = entry + box.innerHTML;
    // Keep max 50 entries
    const entries = box.children;
    if (entries.length > 50) {
        box.removeChild(entries[entries.length - 1]);
    }
}
