        function runDetectionStep() {
            var state = detectionState;
            if (!state.running) return;
            var steps = [
                { name: '���ܼ��', url: '/api/v1/advanced/function/run', key: 'function' },
                { name: '��λ���', url: '/api/v1/advanced/limit/run', key: 'limit' },
                { name: '�ٶȼ��', url: '/api/v1/advanced/speed/run', key: 'speed' }
            ];
            if (state.step >= steps.length) {
                finishDetection();
                return;
            }
            var stepInfo = steps[state.step];
            var pct = Math.round(((state.step) / state.totalSteps) * 100);
            document.getElementById('detectionProgressText').textContent = '���� ' + (state.step + 1) + '/' + state.tot
alSteps + ': ' + stepInfo.name;
            document.getElementById('detectionProgressBar').style.width = pct + '%';
            addDetectionLog('info', '? ���� ' + stepInfo.name + '...');
            apiPost(stepInfo.url, {
                device_ip: state.deviceIp,
                username: (state.device && state.device.username) || 'admin',
                password: (state.device && state.device.password) || '',
                port: (state.device && state.device.port) || 80
            }).then(function(resp) {
                if (resp && resp.success) {
                    state.results[stepInfo.key] = resp.results || {};
                    addDetectionLog('success', '? ' + stepInfo.name + ' ���');
                } else {
                    addDetectionLog('error', '? ' + stepInfo.name + ' ʧ��: ' + (resp ? resp.message : 'δ֪'));
                }
                state.step++;
                var newPct = Math.round((state.step / state.totalSteps) * 100);
                document.getElementById('detectionProgressBar').style.width = newPct + '%';
                runDetectionStep();
            }).catch(function(e) {
                addDetectionLog('error', '? ' + stepInfo.name + ' �쳣: ' + e.message);
                state.step++;
                runDetectionStep();
            });
        }
