arguments.command:
# 修复 WebSocket 路由以匹配带 channel 前缀的路径
$lines = Get-Content "D:\py_app\astro_hub\src\main\main.py"

# 找到 webSocketVideoCtrlProxy 路由行并修改
for ($i = 0; $i -lt $lines.Count; $i++) {
    if ($lines[$i] -match '@app.websocket\("/webSocketVideoCtrlProxy"\)') {
        Write-Output "Found at line $i"
        $lines[$i] = '@app.websocket("/{channel:path}/webSocketVideoCtrlProxy")'
        break
    }
}

# 同时需要修改函数签名添加 channel 参数
for ($i = 0; $i -lt $lines.Count; $i++) {
    if ($lines[$i] -match 'async def websocket_proxy\(websocket: WebSocket\):') {
        Write-Output "Function signature at line $i"
        $lines[$i] = 'async def websocket_proxy(websocket: WebSocket, channel: str):'
        break
    }
}

# 保存
$lines | Set-Content "D:\py_app\astro_hub\src\main\main.py" -Encoding UTF8

Write-Output "Fixed WebSocket route to match channel prefix"

# 验证
Get-Content "D:\py_app\astro_hub\src\main\main.py" | Select-String "@app.websocket|async def websocket_proxy" -Context 0,1
